diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..07860cd75260 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1250,6 +1250,7 @@ Instruction *InstCombinerImpl::visitShl(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   if (Value *V = simplifyLShrInst(I.getOperand(0), I.getOperand(1), I.isExact(),
                                   SQ.getWithInstruction(&I)))
@@ -1550,6 +1551,17 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       }
     }

+    // Reduce add-carry of low-bit integers to logic:
+    // ((X & 1) + (Y & 1)) >> 1 --> (X & 1) & Y
+    Value *X0, *Y0;
+    if (ShAmtC == 1 && match(Op0, m_Add(m_Value(X), m_Value(Y))) &&
+        match(X, m_And(m_Value(X0), m_One())) &&
+        match(Y, m_And(m_Value(Y0), m_One())) &&
+        (X->hasOneUse() || Y->hasOneUse() || Op0->hasOneUse())) {
+      Value *And = Builder.CreateAnd(X0, ConstantInt::get(Ty, 1));
+      return BinaryOperator::CreateAnd(And, Y0);
+    }
+
     // Reduce add-carry of bools to logic:
     // ((zext BoolX) + (zext BoolY)) >> 1 --> zext (BoolX && BoolY)
     Value *BoolX, *BoolY;
@@ -1586,6 +1598,7 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *
 InstCombinerImpl::foldVariableSignZeroExtensionOfVariableHighBitExtract(
     BinaryOperator &OldAShr) {

